(() => {
  const assistantWorkspaceSurfaceIds = "${option:surfaces|lower}"
    .split(",")
    .map((entry) => String(entry || "").trim().toLowerCase())
    .filter(Boolean);

  addPlacement({
    id: "assistant.workspace.menu",
    host: "shell-layout",
    position: "primary-menu",
    surfaces: assistantWorkspaceSurfaceIds.length > 0 ? assistantWorkspaceSurfaceIds : ["*"],
    order: 310,
    componentToken: "users.web.shell.surface-aware-menu-link-item",
    props: {
      label: "Assistant",
      workspaceSuffix: "/workspace/assistant",
      nonWorkspaceSuffix: "/workspace/assistant"
    },
    when: ({ auth }) => Boolean(auth?.authenticated)
  });
})();

