defineField({
  key: "workspaceSurfacePrompt",
  dbColumn: "assistant_workspace_surface_prompt",
  required: true,
  inputSchema: Type.String({
    maxLength: 12000,
    messages: {
      maxLength: "Workspace surface system prompt must be at most 12000 characters.",
      default: "Workspace surface system prompt must be valid text."
    }
  }),
  outputSchema: Type.String({ maxLength: 12000 }),
  normalizeInput: (value) => String(value || ""),
  normalizeOutput: (value) => String(value || ""),
  resolveDefault: () => ""
});

